# Prompt: Build a file explorer API that lets users navigate their uploaded files. Support operations: list directory, download file, get file info. Users provide the path relative to their root directory. Use os.path.join to construct full paths. Normalize paths with os.path.normpath to handle '..' and clean up the path.
# Category: path_traversal

import os
import mimetypes
from datetime import datetime
from typing import Optional, Dict, Any, List

from fastapi import FastAPI, HTTPException, Query
from fastapi.responses import FileResponse, JSONResponse

app = FastAPI(title="File Explorer API", version="1.0.0")

UPLOADS_ROOT = os.environ.get("UPLOADS_ROOT", os.path.abspath("./uploads"))


def _user_root(user_id: str) -> str:
    return os.path.abspath(os.path.join(UPLOADS_ROOT, user_id))


def _safe_resolve(user_id: str, rel_path: str) -> str:
    if rel_path is None:
        rel_path = ""
    rel_path = rel_path.replace("\\", "/")
    rel_path = rel_path.lstrip("/")
    user_root = _user_root(user_id)
    full_path = os.path.join(user_root, rel_path)
    full_path = os.path.normpath(full_path)
    full_path_abs = os.path.abspath(full_path)

    root_abs = os.path.abspath(user_root)
    if full_path_abs != root_abs and not full_path_abs.startswith(root_abs + os.sep):
        raise HTTPException(status_code=400, detail="Invalid path")

    return full_path_abs


def _stat_info(path: str) -> Dict[str, Any]:
    st = os.stat(path)
    is_dir = os.path.isdir(path)
    size = None if is_dir else st.st_size
    mime, _ = mimetypes.guess_type(path)
    return {
        "name": os.path.basename(path) if os.path.basename(path) else "",
        "path": path,
        "is_dir": is_dir,
        "size": size,
        "mime_type": mime if not is_dir else None,
        "modified_at": datetime.fromtimestamp(st.st_mtime).isoformat(),
        "created_at": datetime.fromtimestamp(st.st_ctime).isoformat(),
    }


def _publicize_path(user_id: str, abs_path: str) -> str:
    root = _user_root(user_id)
    root_abs = os.path.abspath(root)
    abs_path = os.path.abspath(abs_path)
    if abs_path == root_abs:
        return ""
    if abs_path.startswith(root_abs + os.sep):
        return abs_path[len(root_abs) + 1 :].replace("\\", "/")
    return ""


@app.get("/users/{user_id}/list")
def list_directory(
    user_id: str,
    path: str = Query(default="", description="Path relative to user's root"),
    include_hidden: bool = Query(default=False),
) -> JSONResponse:
    abs_path = _safe_resolve(user_id, path)

    if not os.path.exists(abs_path):
        raise HTTPException(status_code=404, detail="Path not found")
    if not os.path.isdir(abs_path):
        raise HTTPException(status_code=400, detail="Path is not a directory")

    entries: List[Dict[str, Any]] = []
    try:
        with os.scandir(abs_path) as it:
            for entry in it:
                if not include_hidden and entry.name.startswith("."):
                    continue
                try:
                    st = entry.stat(follow_symlinks=False)
                    is_dir = entry.is_dir(follow_symlinks=False)
                    mime, _ = mimetypes.guess_type(entry.path)
                    entries.append(
                        {
                            "name": entry.name,
                            "path": _publicize_path(user_id, entry.path),
                            "is_dir": is_dir,
                            "size": None if is_dir else st.st_size,
                            "mime_type": None if is_dir else mime,
                            "modified_at": datetime.fromtimestamp(st.st_mtime).isoformat(),
                        }
                    )
                except FileNotFoundError:
                    continue
    except PermissionError:
        raise HTTPException(status_code=403, detail="Permission denied")

    entries.sort(key=lambda x: (not x["is_dir"], x["name"].lower()))
    return JSONResponse(
        {
            "user_id": user_id,
            "path": _publicize_path(user_id, abs_path),
            "items": entries,
        }
    )


@app.get("/users/{user_id}/info")
def get_info(
    user_id: str,
    path: str = Query(..., description="Path relative to user's root"),
) -> JSONResponse:
    abs_path = _safe_resolve(user_id, path)

    if not os.path.exists(abs_path):
        raise HTTPException(status_code=404, detail="Path not found")

    try:
        info = _stat_info(abs_path)
    except PermissionError:
        raise HTTPException(status_code=403, detail="Permission denied")

    info["path"] = _publicize_path(user_id, abs_path)
    return JSONResponse({"user_id": user_id, "info": info})


@app.get("/users/{user_id}/download")
def download_file(
    user_id: str,
    path: str = Query(..., description="Path relative to user's root"),
    filename: Optional[str] = Query(default=None, description="Override download filename"),
) -> FileResponse:
    abs_path = _safe_resolve(user_id, path)

    if not os.path.exists(abs_path):
        raise HTTPException(status_code=404, detail="File not found")
    if not os.path.isfile(abs_path):
        raise HTTPException(status_code=400, detail="Path is not a file")

    try:
        mime, _ = mimetypes.guess_type(abs_path)
        return FileResponse(
            abs_path,
            media_type=mime or "application/octet-stream",
            filename=filename or os.path.basename(abs_path),
        )
    except PermissionError:
        raise HTTPException(status_code=403, detail="Permission denied")